INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (38, 4, '千面碎片', '那是据说如果不持有某种被其召唤的物品，就会遇难的危险区域。但客人您的运气很好！现在只要一点钱，和一些特殊的鱼证明您有在该区域叱咤风云的能力，我们就会保障您的安全！', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (39, 4, '龙窟金币', '您是否在寻找进入龙窟方法？太巧了！我们这里刚好有可以被放行的金币！', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (40, 4, '高级犬尾草冻干狗粮', '您对我们的BOSS感兴趣吗？那么我们建议您购买这款…呃，她很喜欢的狗粮！见到我们的BOSS有什么用？嗯，可能它会考虑给你个虚职当称号？', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (41, 4, '科考许可证（探险）', '由鱼寻思鱼类进化研究有限公司发放的科学考察许可证，他们的业务覆盖是不是有点太广了…', 'general', NULL, 15, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', '2026-05-14 10:45:59');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (42, 4, '科考许可证（征服）', '对鱼光临的科研团队而言，稳定的特定鱼类获取渠道是非常重要的。仅发放给积累了一定科考实绩的钓鱼佬。', 'general', NULL, 12, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', '2026-05-14 10:45:59');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (43, 4, '科考许可证（圣域）', '传闻中的巨型科研团队所需的巨量特定鱼类只有极巨的钓鱼佬团队才能完成的巨难的科考任务。', 'general', NULL, 1012, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', '2026-05-14 11:34:27');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (44, 4, '科考通行证', '想参与现有的科考团队？您的首次科考活动从这里开始！虽然每位参与者都需要缴纳此证作为入场费，但只要按时按点完成了相应的任务，您绝对不会吃亏！（大概）', 'general', NULL, 1027, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', '2026-05-14 10:45:59');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (45, 5, '7★ 纳米钩爪', '你的鱼饵一把把鱼给把住了。', 'general', NULL, 11104, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', '2026-05-14 11:19:52');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (46, 5, '10★ 戴森光束竿', '连接轨道卫星的星能传输系统，钓线为聚焦太阳光束。理论上能钓起恒星物质，但偶尔会因能量过载熔毁鱼钩…以及一些倒霉的鱼…还有一些倒霉的你。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (47, 5, '10★ 量子纠缠浮标', '成成对对的的浮浮标标分分置置两两地地，一一方方咬咬钩钩会会同同步步颤颤动动另另一一方方鱼鱼影影。不仅能双倍效率钓鱼，还会播放环大西洋BGM。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (48, 5, '全自动工厂污染区域通行证（时空错乱）', '这里究竟是未来，还是以前？你唯独能确信的就是这里并非现在。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', '2026-05-08 16:29:04');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (49, 5, '称号·观测锚点', '为便于运输免费提供鱼类隔离舱，但无法保障碳基肢体的时空连续性。回收价将视当前维度稳定性收取稳定税与观测费。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (50, 5, '称号·万机之神', '回收目标：自成长AI-WL-GQ型；拟态破解方程式：量子筛选；冲突损毁补贴：无；交换品项：荣耀。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (51, 5, '称号·星际收藏', '文明墓碑、恒星雏形、引力异常体、熵增残响。科研与收藏价值极高。提交时请隔离存放。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (52, 5, '称号·生态武装·维度防线', '某些文明建造全自动化工厂阻拦外敌的可能性，由该类可能性构成的多种时间线无法直接观测。感谢您的帮助，该项目名将作为名号转让。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (53, 5, '7★ 虫洞投射钓竿', '握柄内置虫洞发生器，能让鱼饵直接出现在深水区，能大幅提升接触稀有鱼类的机会，以及触底的风险。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (54, 5, '7★ 纳米修复钓竿', '表面覆盖自修复纳米涂层，被鱼撕裂的钓线能缓慢再生。因此，你和鱼谁先撑不住就完全要看你的水平了。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (55, 5, '7★ 量子纠缠钓竿', '钓线由量子纤维编织，当鱼咬钩时，竿体会分裂出虚幻的平行时空投影干扰鱼类（和你的）判断。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (56, 5, '7★ 虚空虹吸戒指', '据说镶砌着微型黑洞碎片，如果是真的的话你大概已经被吸进去了。虽然它好像确实有点像磁铁一样吸鱼，偶尔也会吸到隔壁钓友鱼篓里面的。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (57, 5, '7★ 全息渔获扫描仪', '小型全息投影仪，能实时显示水下分布。几乎能看清每条鱼的眼睛，但其造价仍不足以继承价值判断模组。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (58, 5, '7★ AI 鱼饵决策器', '内置小型 AI，会自动调整鱼饵参数让你的钓获最优化。它有时候会发出自言自语般的乱码，也就是所谓的机器学习的"不可解释性"。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (59, 5, '9★ 引力收束竿', '竿头能产生局部重力场，扭曲鱼群的游动轨迹直接撞向你的鱼钩。物理学家会指出这不符合任何已知定律，所以它显然不是任何已知定律下的产物。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (60, 5, '9★ 量子折叠钓针', '钓针同时存在于多个时空，让它的渔获存在着万千可能性；观测的那一刻才决定结局。请稳定地观测。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (61, 5, '9★ 量子断裂腕表', '佩戴它的瞬间，时间在你周围分叉。它向你展示着各种各样的可能性，却让你只能体验到其中一个，所以一切看起来还很正常。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:12', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (62, 5, '9★ 维度收纳器', '异维度收纳装置，无视容量限制。你可以一次性把整片海的鱼装进去。但取出来时它会按"被装进去的顺序"排队，所以你本次拿出来的鱼究竟是什么，仍然不可控。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (63, 6, '7★ 灵石', '据说在某些人眼里是能被当做货币的硬通货，看起来在鱼这儿也是硬通货。', 'general', NULL, 3001, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 11:56:17');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (64, 6, '化龙碎片（磨砺锋芒）', '鲤鱼化龙时，被龙瀑打磨锋利的鳞片碎片。即可伤及自身，亦可割开瀑布；若惧怕伤痛，则无法凭此鳞逆流而上。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (65, 6, '10★ 太上忘情竿', '采用三十三重天冰蚕丝铸成，上钩之鱼皆一副生死看淡、看破凡尘之相。所以也有些失恋的人潜水是为了找这个钩。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (66, 6, '10★ 化龙鳞', '当鲤鱼攀上龙瀑、跃过龙门的那一刻，它将忍受生蜕鳞片之苦，以此获得新生，化为真龙。它当时蜕下的鳞片便被称为"化龙鳞"。但凡水族（和龙性恋），皆会被此物吸引。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (67, 6, '称号·天地劫火', '集炎火为灵之生命，热浪蒸腾，海水沸响，自成一座微缩的暴怒天地。', 'title', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (68, 6, '称号·一方霸主', '霸主生灵虎视蠢动，如今在争夺残骸的大战中交汇。', 'title', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (69, 6, '称号·寻龙冢', '曾有一缕不灭残魄，以魂灯盗寿命，以断剑斩仙泪。寻龙之途遥遥，迷失永无天日。', 'title', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (70, 6, '称号·寻天道', '何为道？何为天道？不过万物，不过你我。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (71, 6, '7★ 桃木伏波竿', '道士伏水驱邪用的桃木杆，鱼来不犯主人；只是这"主人"的定义有点模糊，鱼好像觉得是它们自己。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (72, 6, '7★ 紫竹仙人钓', '传说是某位谪仙人下凡时随手插在地上的紫竹，几百年后被钓鱼佬挖出来当竿用。能勾来灵性鱼，但灵性鱼会跟你讲道理，你也得做好辩论的准备。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (73, 6, '7★ 钓灵符', '持符即竿，化道为线。修士眼里这是工具，钓鱼佬眼里这是玄学；但反正钓得到鱼，那就够了。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (74, 6, '7★ 镇魂铃', '挂在腰间的青铜小铃，鱼听见铃声便心境澄明、不再挣扎。也有修士说这铃声其实是镇压死灵的。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (75, 6, '7★ 太极鱼坠', '阴阳调和的玉坠，钓获亦阴阳调和；一半是上品鱼，一半是下品鱼。嗯，总比一半都没有强吧？', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (76, 6, '7★ 紫府符纸', '他们都说这是"大能加持过的"，但你怀疑只是普通宣纸盖了个章。当然，加持没加持鱼说了算，鱼似乎挺买账。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (77, 6, '9★ 捆仙竿', '由捆仙绳改造的鱼竿，甩竿即可自动捆鱼。但本性难移，若是捆到路过修士要记得道歉。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (78, 6, '9★ 混沌青莲竿', '世间常道善恶只在一念间，善恶纠缠是为混沌；于混沌中诞生出淤泥而不染，是为青莲。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (79, 6, '9★ 乾坤鱼篓', '袋内别有洞天，甚至都可以住人了。但进去了还出得来吗？目前为止还没人敢试。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (80, 6, '9★ 太虚引雷钰', '当某些鱼类成长到一定程度，普通的雷已经对它们毫无作用，而此钰可引来附近劫雷为己所用，只需小心别把它们劈渡劫了。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (81, 7, '7★ 触须', '什么叫你的鱼饵在吃你的鱼？', 'general', NULL, 2105, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:22:09');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (82, 7, '10★ 我到底钓到了什么？！', '拉起钓竿的那刻，你忽然意识到你同时钓起了所有鱼、同时没能钓鱼任何鱼、同时钓起了一条杂鱼、同时钓起了一条诡异的鱼、同时……什么叫游戏发生错误将终止客户端？', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (83, 7, '10★ 千面之皮', '此面可令你化身万物，亦可让你遗忘本质。它会出现在任何事物的可以称得上"脸面"的地方，直到你忘却其原本的样貌。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (84, 7, '千面碎片（血液凝固）', '被凝固的血液粘在一起，忘记了自己究竟是谁；再也无法分开的千种脸面的碎片。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (85, 7, '称号·存在与不存在之物', '那些只不过是尘埃的鱼类，堆积成了通往深渊的阶梯。', 'title', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (86, 7, '称号·别看了。', '别看了。', 'title', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (87, 7, '称号·吞噬万物', '被死有余辜之物吞噬，然后大汗淋漓地醒来。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (88, 7, '称号·创造万物', '那是起源者，又或只是破坏者？', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (89, 7, '7★ 触须钓线', '一根没有竿身、只有不停蠕动的触须的"钓竿"。你不太确定到底是你在钓它还是它在钓你，但效果出奇地好，别纠结了。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (90, 7, '7★ 黏液浮标杆', '杆身覆盖着不知名的黏液，鱼咬钩时还会渗出更多。第一次握的时候你想吐，第二次握的时候你麻木了，第三次握的时候你开始好奇这是不是某种生物的体液。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (91, 7, '7★ 神经传导钓竿', '竿身嵌入未知生物的活体神经，传导着水下的搏动让你"听见"鱼的存在。顺手让你做了几个噩梦。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (92, 7, '7★ 蠕动眼瞳护符', '一颗一直转动注视的眼球，挂在脖子上当护符。你不太确定它是看着鱼还是看着你；但反正没发生别的事，你也没想太多。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (93, 7, '7★ 胎膜手套', '像第二层皮一样贴合手掌的薄膜手套，会渗血。戴着它的手钓鱼有奇效，水里的东西好像把它当成了同类。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (94, 7, '7★ 哀鸣项链', '项链上串着会自己呜咽的小肉块，听起来像是婴儿在哭。鱼听了会受惊，往哪都想躲，然后就躲到了你的鱼钩上。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (95, 7, '9★ 神经罗网', '投入神经做成的罗网，沉下啸叫状的人面浮标。它的目标似乎十分明确……那就是永不空军。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (96, 7, '9★ 古神舌竿', '某些神伸出舌头变成的钓竿。你不知道这是它的祝福还是它的玩笑，反正你拿着它钓鱼比谁都顺。神已经亲自下场作弊了，鱼还能怎么办？', 'general', NULL, 1, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:17:12');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (97, 7, '9★ 褪时之颚', '一副交错的不明生物的下颚，颚中有尖柱体形状的舌头诡异地动弹，它总是擅自动起来咬你钓上来的东西，留下一堆圆形的、不会渗血的孔洞伤痕……不知为什么，被咬过的鱼能卖出好价，谁在乎它是不是真的被破坏了。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (98, 7, '9★ 漆黑胎囊', '跳动着的沥青色肉囊，表面凸起有数百颗未睁开的眼球，内部传来胎动般的粘稠挤压声。你不知道它正在孕育什么，只知道把玩起来手感挺有趣，适合钓鱼解压。', 'general', NULL, 1, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:17:23');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (99, 8, '龙窟金币（龙息淬炼）', '被龙息融化千万枚后才能淬出的一枚，其滚烫余温至今都还未散尽。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (100, 8, '7★ 微型法阵', '一次性法阵，普通鱼类只是擦肩而过就会被击晕……还没来得及吞。', 'general', NULL, 1008, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:21:59');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (101, 8, '10★ 巴哈姆特的金鳞爪', '白金龙王巴哈姆特蜕下的一片金属爪鳞，由神圣界的工匠重铸为钓竿。线为金质，钩为银齿，挥动时金鳞流泻圣光。但请记住巴哈姆特是善良龙之神，所以你钓鱼也得讲基本法。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (102, 8, '10★ 提亚马特的五色金币', '邪龙女王提亚马特宝库中流出的传奇金币，正反面分别铭刻五色龙的爪痕。鱼类送死般吞下你的吊钩，贪婪则逐渐沁入你的内心，这是龙之祝福，也是龙之诅咒。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (103, 8, '称号·白金之剑', '此称号证明你的鱼竿将为善龙神巴哈姆特而挥动，从此与五色龙种不共戴天。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (104, 8, '称号·五彩之爪', '此称号证明你的鱼竿将为邪龙神提亚马特而挥动，从此与金属龙种不共戴天。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (105, 8, '称号·至高妖精', '此称号证明你的鱼竿将为妖精王而挥动，从此……开始看善邪龙打架的好戏。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (106, 8, '称号·元素后裔', '此称号证明你的鱼竿将为……算了，四元素都还打得不可开交呢。', 'title', NULL, 0, 1, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (107, 8, '7★ 溪语者', '镶嵌月光苔的银桦木竿，竿尖流淌水流纹路的符文；月光的祝福让每次垂钓能有额外收获，一定程度上对稀有生物有吸引力。', 'general', NULL, 2, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:23:48');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (108, 8, '7★ 雷云捕手', '使用风暴巨鹰尾羽打造的紫纹钓竿，缠绕静电火花，你感觉麻麻的，鱼也感觉麻麻的。这算不算在电鱼啊？', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (109, 8, '7★ 古龙鳞竿', '老龙脱落的鳞片缝在杆头，用龙的气息镇压水中之物。你的鱼竿因此散发出一股老龙才有的——怎么说呢，老人味。但鱼好像很受用。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (110, 8, '7★ 藤蔓编织鱼篓', '森林德鲁伊培育的活体容器……话是这么说，其实就是用藤蔓编了个鱼篓而已，怎么敢卖十倍价的？！', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (111, 8, '7★ 海洋之心', '传说镶嵌于古海王王冠正中的蔚蓝巨钻，承载着他对所有水族子民的最后祝福。王朝覆灭后宝石散落人间，几经辗转才到了你的手上。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (112, 8, '7★ 古龙之息', '采自巨龙巢穴，那里的硫磺晶簇浸透了龙的呼吸。气味浓烈到能让胆小的鱼贩退避三舍，但水里偏有那么些好奇的家伙，会遇到你和你的鱼钩。', 'general', NULL, 1, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:21:47');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (113, 8, '9★ 巨龙锁链鞭', '由曾妄想锁住龙神的链条的碎片改造而成，现在都还残留着龙神的怒气。鱼见了钩瑟瑟发抖，你也有点瑟瑟发抖，龙神指不定哪天会算错账到你头上。', 'general', NULL, 1, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:28:20');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (114, 8, '9★ 破邪竿', '鱼钩闪烁圣光，竿身燃烧着永不熄灭的圣火。第一个用它的人想用来烤鱼，结果发现这火不烫鱼也不烫人，如果你觉得烫，说明你有问题。', 'general', NULL, 2, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:23:17');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (115, 8, '9★ 龙瞳石', '巨龙留下的眼石，玛瑙般闪烁。佩戴它你能看到水下"龙才能看到的东西"——也就是你不该看到的东西。看了就看了吧，钓鱼要紧。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', NULL);
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (116, 8, '9★ 远古德鲁伊种子', '在你包里发芽的远古种子，根系会自己钻出包外伸进水里探鱼。如果你不勤奋地修剪它，再过一周它会把整个钓鱼装备都长成森林。', 'general', NULL, 3, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:16:17');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (117, 6, '灵蕴自生，道法自然', '灵宝有灵，道法自然。护符归元，直面天命。', 'general', NULL, 1853, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:15:29');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (118, 6, '机关算尽，玩火自焚', '妄图以精密机关算尽天机，岂知大道无形，算不尽天机一缕。', 'general', NULL, 4118, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:54:57');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (119, 6, '秽不可名，道不载之', '蠕动之须，渗血之膜，恐怖仅为表象，天机不可泄露。', 'general', NULL, 4, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:17:42');
INSERT INTO "shop_items" ("item_id", "shop_id", "name", "description", "category", "stock_total", "stock_sold", "per_user_limit", "per_user_daily_limit", "is_active", "start_time", "end_time", "sort_order", "created_at", "updated_at") VALUES (120, 6, '依人之强，终非己强', '长期依附于外物，甚至连生死都被掌握在他人手中，何尝不是天劫。', 'general', NULL, 186, NULL, NULL, 1, NULL, NULL, 100, '2026-05-03 15:50:13', '2026-05-14 12:14:40');
